#![forbid(unsafe_code)]

#[path = "../ts_emit.rs"]
mod ts_emit;

use rulebench_authority::{
    combat_session_transcripts, CombatLogEntry, CombatSessionStepReadout, CombatSessionStepSummary,
    CombatSessionSummary, CommandAttempt, CommandOutcomeClass, ScenarioMetadata,
    ScenarioProjection,
};
use ts_emit::{render_scenario_readout, ts_string, ts_string_array};

fn main() {
    print!("{}", render_combat_session_catalog());
}

fn render_combat_session_catalog() -> String {
    let transcripts = combat_session_transcripts();
    let mut out = String::from(
        "// GENERATED by rulebench-authority Rust combat session transcript. Do not hand-edit.\n\n",
    );
    out.push_str(
        "import type { RulebenchCombatSessionCatalogDto } from '@asha-rulebench/protocol';\n\n",
    );
    out.push_str(
        "export const rustBackedCombatSessionCatalog: RulebenchCombatSessionCatalogDto = {\n",
    );
    out.push_str("  summaries: [\n");
    for transcript in &transcripts {
        out.push_str(&render_session_summary(&transcript.summary));
    }
    out.push_str("  ],\n");
    out.push_str("  readouts: [\n");
    for transcript in &transcripts {
        for readout in &transcript.steps {
            out.push_str(&render_step_readout(readout));
        }
    }
    out.push_str("  ],\n");
    out.push_str("};\n");
    out
}

fn render_session_summary(summary: &CombatSessionSummary) -> String {
    let mut out = String::from("    {\n");
    out.push_str(&format!("      id: {},\n", ts_string(&summary.id)));
    out.push_str(&format!("      title: {},\n", ts_string(&summary.title)));
    out.push_str(&format!(
        "      summary: {},\n",
        ts_string(&summary.summary)
    ));
    out.push_str(&format!(
        "      seedLabel: {},\n",
        ts_string(&summary.seed_label)
    ));
    out.push_str("      steps: [\n");
    for step in &summary.steps {
        out.push_str(&render_step_summary(step, "        "));
    }
    out.push_str("      ],\n");
    out.push_str("    },\n");
    out
}

fn render_step_readout(readout: &CombatSessionStepReadout) -> String {
    let mut scenario = readout.scenario.clone();
    scenario.metadata = ScenarioMetadata {
        id: readout.step.id.clone(),
        title: readout.step.title.clone(),
        summary: readout.step.summary.clone(),
        seed_label: format!(
            "roll-stream:{}",
            readout
                .command
                .roll_stream
                .iter()
                .map(i32::to_string)
                .collect::<Vec<_>>()
                .join(",")
        ),
    };
    let target = readout
        .receipt
        .target_legality
        .as_ref()
        .expect("session readout has target legality");

    let mut out = String::from("    {\n");
    out.push_str(&format!(
        "      sessionId: {},\n",
        ts_string(&readout.session_id)
    ));
    out.push_str("      step: ");
    out.push_str(&render_step_summary(&readout.step, "      "));
    out.push_str("      command: ");
    out.push_str(&render_command(&readout.command, "      "));
    out.push_str("      scenarioReadout: ");
    out.push_str(&render_scenario_readout(
        &scenario,
        &readout.receipt.events,
        &readout.receipt.trace,
        &readout.state_after,
        target,
        "      ",
    ));
    out.push_str(",\n");
    out.push_str("      combatLog: [\n");
    for entry in &readout.combat_log {
        out.push_str(&render_log_entry(entry, "        "));
    }
    out.push_str("      ],\n");
    out.push_str("      stateBefore: ");
    out.push_str(&render_state(&readout.state_before, "      "));
    out.push_str(",\n");
    out.push_str("      stateAfter: ");
    out.push_str(&render_state(&readout.state_after, "      "));
    out.push_str(",\n");
    out.push_str("    },\n");
    out
}

fn render_step_summary(step: &CombatSessionStepSummary, indent: &str) -> String {
    let mut out = String::from("{\n");
    out.push_str(&format!("{indent}  id: {},\n", ts_string(&step.id)));
    out.push_str(&format!("{indent}  index: {},\n", step.index));
    out.push_str(&format!("{indent}  title: {},\n", ts_string(&step.title)));
    out.push_str(&format!(
        "{indent}  summary: {},\n",
        ts_string(&step.summary)
    ));
    out.push_str(&format!(
        "{indent}  outcomeClass: {},\n",
        ts_string(outcome_class(step.outcome_class))
    ));
    out.push_str(&format!("{indent}  logIndex: {},\n", step.log_index));
    out.push_str(&format!("{indent}}},\n"));
    out
}

fn render_command(command: &CommandAttempt, indent: &str) -> String {
    let roll_stream = command
        .roll_stream
        .iter()
        .map(i32::to_string)
        .collect::<Vec<_>>()
        .join(", ");
    let mut out = String::from("{\n");
    out.push_str(&format!(
        "{indent}  stepId: {},\n",
        ts_string(&command.step_id)
    ));
    out.push_str(&format!("{indent}  stepIndex: {},\n", command.step_index));
    out.push_str(&format!(
        "{indent}  actorId: {},\n",
        ts_string(&command.actor_id)
    ));
    out.push_str(&format!(
        "{indent}  actionId: {},\n",
        ts_string(&command.action_id)
    ));
    out.push_str(&format!(
        "{indent}  targetId: {},\n",
        ts_string(&command.target_id)
    ));
    out.push_str(&format!("{indent}  rollStream: [{roll_stream}],\n"));
    out.push_str(&format!(
        "{indent}  outcomeClass: {},\n",
        ts_string(outcome_class(command.outcome_class))
    ));
    out.push_str(&format!("{indent}}},\n"));
    out
}

fn render_log_entry(entry: &CombatLogEntry, indent: &str) -> String {
    let mut out = String::from("{\n");
    out.push_str(&format!("{indent}  id: {},\n", ts_string(&entry.id)));
    out.push_str(&format!(
        "{indent}  stepId: {},\n",
        ts_string(&entry.step_id)
    ));
    out.push_str(&format!("{indent}  logIndex: {},\n", entry.log_index));
    out.push_str(&format!("{indent}  title: {},\n", ts_string(&entry.title)));
    out.push_str(&format!(
        "{indent}  summary: {},\n",
        ts_string(&entry.summary)
    ));
    out.push_str(&format!(
        "{indent}  outcomeClass: {},\n",
        ts_string(outcome_class(entry.outcome_class))
    ));
    out.push_str(&format!(
        "{indent}  eventTypes: {},\n",
        ts_string_array(&entry.event_types)
    ));
    out.push_str(&format!("{indent}}},\n"));
    out
}

fn render_state(state: &ScenarioProjection, indent: &str) -> String {
    let mut out = String::from("{\n");
    out.push_str(&format!(
        "{indent}  summary: {},\n",
        ts_string(&state.summary)
    ));
    out.push_str(&format!("{indent}  combatants: [\n"));
    for combatant in &state.combatants {
        out.push_str(&format!("{indent}    {{\n"));
        out.push_str(&format!(
            "{indent}      id: {},\n",
            ts_string(&combatant.id)
        ));
        out.push_str(&format!(
            "{indent}      name: {},\n",
            ts_string(&combatant.name)
        ));
        out.push_str(&format!(
            "{indent}      hitPoints: {{ current: {}, max: {} }},\n",
            combatant.hit_points.current, combatant.hit_points.max
        ));
        out.push_str(&format!(
            "{indent}      conditions: {},\n",
            ts_string_array(&combatant.conditions)
        ));
        out.push_str(&format!("{indent}    }},\n"));
    }
    out.push_str(&format!("{indent}  ],\n"));
    out.push_str(&format!("{indent}}}"));
    out
}

fn outcome_class(outcome_class: CommandOutcomeClass) -> &'static str {
    match outcome_class {
        CommandOutcomeClass::AcceptedHit => "acceptedHit",
        CommandOutcomeClass::AcceptedMiss => "acceptedMiss",
        CommandOutcomeClass::RejectedTargetLegality => "rejectedTargetLegality",
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    const GENERATED_SESSION: &str =
        include_str!("../../../../../libs/transport/src/generated/rust-combat-session.ts");

    #[test]
    fn committed_transport_session_artifact_matches_rust_authority_output() {
        assert_eq!(render_combat_session_catalog(), GENERATED_SESSION);
    }
}
